#include <iostream>
#include <string>
#include <vector>
#include <cstdlib>
#include <ctime>

class Player {
private:
    std::string name;
    int health;
    int maxHealth;
    int attack;
    int defense;
    int level;
    int experience;
    std::vector<std::string> inventory;

public:
    Player(std::string n, int h, int a, int d) {
        name = n;
        health = h;
        maxHealth = h;
        attack = a;
        defense = d;
        level = 1;
        experience = 0;
        std::srand(std::time(0));
    }

    // --- Combat functions ---
    void attackEnemy(Player& enemy) {
        int damage = attack + (std::rand() % 5);  // Random bonus
        std::cout << name << " attacks " << enemy.getName() << " for " << damage << " damage!" << std::endl;
        enemy.takeDamage(damage);
    }

    void takeDamage(int damage) {
        int actualDamage = damage - (defense / 2);
        if (actualDamage < 0) actualDamage = 0;
        health -= actualDamage;
        if (health < 0) health = 0;
        std::cout << name << " took " << actualDamage << " damage!" << std::endl;
        if (health == 0) {
            std::cout << name << " has been defeated!" << std::endl;
        }
    }

    void heal(int amount) {
        health += amount;
        if (health > maxHealth) health = maxHealth;
        std::cout << name << " healed " << amount << " HP!" << std::endl;
    }

    // --- Inventory functions ---
    void addItem(const std::string& item) {
        inventory.push_back(item);
        std::cout << name << " added " << item << " to inventory." << std::endl;
    }

    bool hasItem(const std::string& item) const {
        for (const std::string& i : inventory) {
            if (i == item) return true;
        }
        return false;
    }

    void showInventory() const {
        std::cout << name << "'s Inventory:" << std::endl;
        if (inventory.empty()) {
            std::cout << "  (empty)" << std::endl;
            return;
        }
        for (const std::string& item : inventory) {
            std::cout << "  - " << item << std::endl;
        }
    }

    // --- Leveling functions ---
    void gainExperience(int exp) {
        experience += exp;
        std::cout << name << " gained " << exp << " experience!" << std::endl;

        int requiredExp = level * 100;
        if (experience >= requiredExp) {
            levelUp();
        }
    }

    void levelUp() {
        level++;
        maxHealth += 20;
        health = maxHealth;
        attack += 5;
        defense += 3;
        experience = 0;
        std::cout << "*** " << name << " reached level " << level << "! ***" << std::endl;
        std::cout << "Health +20, Attack +5, Defense +3" << std::endl;
    }

    // --- Status functions ---
    void displayStats() const {
        std::cout << "\n=== " << name << " ===" << std::endl;
        std::cout << "Level: " << level << std::endl;
        std::cout << "Health: " << health << "/" << maxHealth << std::endl;
        std::cout << "Attack: " << attack << std::endl;
        std::cout << "Defense: " << defense << std::endl;
        std::cout << "Experience: " << experience << "/" << (level * 100) << std::endl;
    }

    bool isAlive() const { return health > 0; }

    // --- Getters ---
    std::string getName() const { return name; }
    int getHealth() const { return health; }
    int getAttack() const { return attack; }
    int getDefense() const { return defense; }
    int getLevel() const { return level; }
};

int main() {
    std::cout << "=== Member Functions in Action ===" << std::endl;

    Player hero("Aragorn", 120, 25, 15);
    Player goblin("Goblin", 40, 10, 5);

    hero.displayStats();
    goblin.displayStats();

    // Combat
    hero.attackEnemy(goblin);
    goblin.attackEnemy(hero);

    // Inventory
    hero.addItem("Health Potion");
    hero.addItem("Iron Sword");
    hero.showInventory();

    // Check item
    if (hero.hasItem("Health Potion")) {
        std::cout << "Hero has a Health Potion!" << std::endl;
        hero.heal(30);
    }

    // Experience
    hero.gainExperience(80);
    hero.displayStats();

    return 0;
}

