#include <iostream>
#include <string>
#include <cstdlib>
#include <ctime>

class Character {
private:
    std::string name;
    int health;
    int attack;

public:
    Character(std::string n, int h, int a) {
        name = n;
        health = h;
        attack = a;
        std::srand(std::time(0));
    }

    void attackEnemy(Character& target) {
        int damage = attack + (std::rand() % 6);
        std::cout << name << " attacks " << target.getName() 
                  << " for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);
    }

    void takeDamage(int damage) {
        health -= damage;
        if (health < 0) health = 0;
        std::cout << name << " took " << damage << " damage!" << std::endl;
        if (!isAlive()) {
            std::cout << name << " has been defeated!" << std::endl;
        }
    }

    bool isAlive() const {
        return health > 0;
    }

    void displayStats() const {
        std::cout << name << " - Health: " << health << "/100" 
                  << (isAlive() ? " (Alive)" : " (Dead)") << std::endl;
    }

    std::string getName() const { return name; }
};

int main() {
    Character hero("Aragorn", 100, 20);
    Character orc("Orc", 80, 15);

    std::cout << "=== Initial Stats ===" << std::endl;
    hero.displayStats();
    orc.displayStats();

    std::cout << "\n=== Battle! ===" << std::endl;
    for (int i = 0; i < 3; i++) {
        hero.attackEnemy(orc);
        if (orc.isAlive()) {
            orc.attackEnemy(hero);
        }
        std::cout << std::endl;
    }

    std::cout << "=== Final Stats ===" << std::endl;
    hero.displayStats();
    orc.displayStats();

    std::cout << "\nHero " << (hero.isAlive() ? "is alive!" : "has fallen!") << std::endl;
    std::cout << "Orc " << (orc.isAlive() ? "is alive!" : "has fallen!") << std::endl;

    return 0;
}
